import { clerkOrgSlugSchema } from "@repo/app-validation";
import { createPlatformCaller } from "@repo/platform-trpc/caller";
import type { TRPCRouterRecord } from "@trpc/server";
import { TRPCError } from "@trpc/server";
import { clerkClient } from "@vendor/clerk/server";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { z } from "zod";
import { userScopedProcedure, verifyOrgMembership } from "../../trpc";

/**
 * Organization router - Clerk-based organization management
 *
 * Phase 1.6: Organizations are managed entirely in Clerk (source of truth)
 * No database table for organizations - Clerk handles all org data
 */
export const organizationRouter = {
  /**
   * List user's organizations from Clerk
   *
   * Returns all organizations the authenticated user belongs to.
   * Used by org-switcher component in the header.
   */
  listUserOrganizations: userScopedProcedure.query(async ({ ctx }) => {
    // userScopedProcedure guarantees clerk-pending or clerk-active
    const userId = ctx.auth.userId;
    const clerk = await clerkClient();

    // Get all organizations the user belongs to from Clerk
    const { data: memberships } =
      await clerk.users.getOrganizationMembershipList({
        userId,
      });

    // Return Clerk organization data directly
    return memberships.map((membership) => {
      const clerkOrg = membership.organization;

      return {
        id: clerkOrg.id, // Clerk org ID
        slug: clerkOrg.slug,
        name: clerkOrg.name,
        role: membership.role,
        imageUrl: clerkOrg.imageUrl,
      };
    });
  }),

  /**
   * Get GitHub App install URL for org creation.
   * No active org required — the install creates a pending installation.
   */
  getGitHubInstallUrl: userScopedProcedure.query(async ({ ctx }) => {
    const platform = await createPlatformCaller();
    const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? "http://localhost:3024";

    return platform.connections.getAuthorizeUrl({
      provider: "github",
      connectedBy: ctx.auth.userId,
      redirectTo: `${appUrl}/account/teams/new`,
    });
  }),

  /**
   * Create organization
   * Creates a new Clerk organization with the user as admin
   *
   * Used by team creation flow at /account/teams/new
   * Does NOT create a default project - user sets up integrations separately
   */
  create: userScopedProcedure
    .input(
      z.object({
        slug: clerkOrgSlugSchema,
      })
    )
    .mutation(async ({ ctx, input }) => {
      // userScopedProcedure guarantees clerk-pending or clerk-active
      log.info("[organization] create", {
        slug: input.slug,
        userId: ctx.auth.userId,
        authType: ctx.auth.type,
      });

      const clerk = await clerkClient();

      try {
        // Create Clerk organization (slug used for both name and slug)
        const clerkOrg = await clerk.organizations.createOrganization({
          name: input.slug,
          slug: input.slug,
          createdBy: ctx.auth.userId,
        });

        log.info("[organization] create success", {
          organizationId: clerkOrg.id,
          slug: clerkOrg.slug,
        });

        return {
          organizationId: clerkOrg.id,
          slug: clerkOrg.slug || input.slug,
        };
      } catch (error: unknown) {
        log.error("[organization] create failed", {
          slug: input.slug,
          userId: ctx.auth.userId,
          error: parseError(error),
          errorDetails: error,
        });

        // Check for specific Clerk errors
        if (error && typeof error === "object" && "errors" in error) {
          const clerkError = error as {
            errors?: { code: string; message: string }[];
          };

          log.error("[organization] clerk error details", {
            errors: clerkError.errors,
          });

          if (
            clerkError.errors?.[0]?.code === "duplicate_record" ||
            clerkError.errors?.[0]?.code === "form_identifier_exists" ||
            clerkError.errors?.[0]?.message.includes("already exists") ||
            clerkError.errors?.[0]?.message.includes("slug is taken")
          ) {
            throw new TRPCError({
              code: "CONFLICT",
              message: `An organization with the name "${input.slug}" already exists`,
            });
          }
        }

        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Failed to create organization",
          cause: error,
        });
      }
    }),

  /**
   * Update organization name
   * Used by team settings page to update the organization name/slug in Clerk
   *
   * Only organization admins can update the organization name
   */
  updateName: userScopedProcedure
    .input(
      z.object({
        slug: z.string().min(1, "Organization slug is required"),
        name: clerkOrgSlugSchema,
      })
    )
    .mutation(async ({ ctx, input }) => {
      // userScopedProcedure guarantees clerk-pending or clerk-active
      const clerk = await clerkClient();

      try {
        // Get organization by slug
        const org = await clerk.organizations.getOrganization({
          slug: input.slug,
        });

        // Verify user has admin access to the organization
        await verifyOrgMembership({
          clerkOrgId: org.id,
          userId: ctx.auth.userId,
          requireAdmin: true,
        });

        // Update organization in Clerk
        await clerk.organizations.updateOrganization(org.id, {
          name: input.name,
          slug: input.name, // Clerk uses slug for URL-safe names
        });

        log.info("[organization] updateName success", {
          organizationId: org.id,
          slug: input.name,
          userId: ctx.auth.userId,
        });

        return {
          success: true,
          id: org.id, // Return org ID for setActive calls
          name: input.name,
        };
      } catch (error: unknown) {
        // Re-throw TRPCError as-is
        if (error instanceof TRPCError) {
          throw error;
        }

        log.error("[organization] updateName failed", {
          slug: input.slug,
          userId: ctx.auth.userId,
          error: parseError(error),
        });

        // Check for specific Clerk errors
        if (error && typeof error === "object" && "errors" in error) {
          const clerkError = error as {
            errors?: { code: string; message: string }[];
          };

          if (
            clerkError.errors?.[0]?.code === "duplicate_record" ||
            clerkError.errors?.[0]?.code === "form_identifier_exists" ||
            clerkError.errors?.[0]?.message.includes("already exists") ||
            clerkError.errors?.[0]?.message.includes("slug is taken")
          ) {
            throw new TRPCError({
              code: "CONFLICT",
              message: `An organization with the name "${input.name}" already exists`,
            });
          }
        }

        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Failed to update organization",
          cause: error,
        });
      }
    }),
} satisfies TRPCRouterRecord;

import { Icons } from "@repo/ui/components/icons";
import { TeamNameForm } from "./_components/team-name-form";

export const dynamic = "force-dynamic";

export default function CreateTeamPage() {
  return (
    <div className="flex flex-1 items-center justify-center px-4 pb-32">
      <div className="w-full max-w-md space-y-4">
        {/* Logo */}
        <div className="w-fit rounded-sm bg-card p-3">
          <Icons.logoShort className="h-5 w-5 text-foreground" />
        </div>

        <div className="space-y-4">
          <h1 className="pb-4 font-medium font-pp text-2xl text-foreground">
            Create your team
          </h1>
          <TeamNameForm />
        </div>
      </div>
    </div>
  );
}

import type { ProviderAccountInfo, SourceType } from "@repo/app-providers";
import type { GwInstallationBackfillConfig } from "@repo/app-providers/contracts";
import type { ClerkUserId } from "@repo/app-validation";
import { nanoid } from "@repo/lib";
import { sql } from "drizzle-orm";
import {
  index,
  integer,
  jsonb,
  pgTable,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";

export const gatewayInstallations = pgTable(
  "lightfast_gateway_installations",
  {
    id: varchar("id", { length: 191 })
      .notNull()
      .primaryKey()
      .$defaultFn(() => nanoid()),

    provider: varchar("provider", { length: 50 }).notNull().$type<SourceType>(),
    externalId: varchar("external_id", { length: 191 }).notNull(),
    connectedBy: varchar("connected_by", { length: 191 })
      .notNull()
      .$type<ClerkUserId>(),
    orgId: varchar("org_id", { length: 191 }).notNull(),

    providerOrgId: varchar("provider_org_id", { length: 191 }),
    providerOrgLogin: varchar("provider_org_login", { length: 191 }),

    status: varchar("status", { length: 50 }).notNull(), // active|pending|error|revoked

    /**
     * Provider-specific installation metadata (JSONB) — discriminated union by sourceType.
     *
     * Schema: providerAccountInfoSchema from @repo/app-providers
     *
     * DESIGN INVARIANT:
     * - `raw` = non-secret fields from the token exchange / OAuth response only
     * - NEVER store display names (account login, org name, avatar, slug) here
     * - Display data is resolved live via provider APIs in connections.*.list/get
     * - This column stores identity + operational data, not presentation data
     *
     * NEVER add resource-specific data (repos[], projects[], teams[]) — those
     * belong in providerConfig on gateway_installations, one row per resource.
     */
    providerAccountInfo: jsonb(
      "provider_account_info"
    ).$type<ProviderAccountInfo>(),

    /** Optional backfill configuration for this installation. */
    backfillConfig:
      jsonb("backfill_config").$type<GwInstallationBackfillConfig>(),

    // Health monitoring columns
    healthStatus: varchar("health_status", { length: 50 })
      .notNull()
      .default("unknown"),
    lastHealthCheckAt: timestamp("last_health_check_at", {
      mode: "string",
      withTimezone: true,
    }),
    healthCheckFailures: integer("health_check_failures").notNull().default(0),

    createdAt: timestamp("created_at", { mode: "string", withTimezone: true })
      .notNull()
      .defaultNow(),
    updatedAt: timestamp("updated_at", { mode: "string", withTimezone: true })
      .notNull()
      .defaultNow()
      .$onUpdateFn(() => sql`CURRENT_TIMESTAMP`),
  },
  (table) => ({
    providerExternalIdx: uniqueIndex("gateway_inst_provider_external_idx").on(
      table.provider,
      table.externalId
    ),
    orgIdIdx: index("gateway_inst_org_id_idx").on(table.orgId),
    orgProviderIdx: index("gateway_inst_org_provider_idx").on(
      table.orgId,
      table.provider
    ),
    connectedByIdx: index("gateway_inst_connected_by_idx").on(
      table.connectedBy
    ),
    providerOrgIdx: uniqueIndex("gateway_inst_provider_org_idx").on(
      table.provider,
      table.providerOrgId
    ),
  })
);

export type GatewayInstallation = typeof gatewayInstallations.$inferSelect;
export type InsertGatewayInstallation =
  typeof gatewayInstallations.$inferInsert;

import type { ProviderAccountInfo, SourceType } from "@repo/app-providers";
import type { ClerkUserId } from "@repo/app-validation";
import { nanoid } from "@repo/lib";
import {
  index,
  jsonb,
  pgTable,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";

export const pendingInstallations = pgTable(
  "lightfast_pending_installations",
  {
    id: varchar("id", { length: 191 })
      .notNull()
      .primaryKey()
      .$defaultFn(() => nanoid()),

    provider: varchar("provider", { length: 50 }).notNull().$type<SourceType>(),
    externalId: varchar("external_id", { length: 191 }).notNull(),

    providerOrgId: varchar("provider_org_id", { length: 191 }).notNull(),
    providerOrgLogin: varchar("provider_org_login", { length: 191 }).notNull(),
    providerOrgAvatarUrl: varchar("provider_org_avatar_url", { length: 500 }),

    connectedBy: varchar("connected_by", { length: 191 })
      .notNull()
      .$type<ClerkUserId>(),

    providerAccountInfo: jsonb(
      "provider_account_info"
    ).$type<ProviderAccountInfo>(),

    createdAt: timestamp("created_at", { mode: "string", withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (table) => ({
    providerExternalIdx: uniqueIndex("pending_inst_provider_external_idx").on(
      table.provider,
      table.externalId
    ),
    connectedByIdx: index("pending_inst_connected_by_idx").on(
      table.connectedBy
    ),
  })
);

export type PendingInstallation = typeof pendingInstallations.$inferSelect;
export type InsertPendingInstallation =
  typeof pendingInstallations.$inferInsert;

