"use client";

import { useTRPC } from "@repo/app-trpc/react";
import { Button } from "@repo/ui/components/ui/button";
import {
  useMutation,
  useQueryClient,
  useSuspenseQuery,
} from "@tanstack/react-query";
import { useOrganizationList } from "@vendor/clerk/client";
import { Github, Loader2 } from "lucide-react";
import Image from "next/image";
import { useRouter } from "next/navigation";
import { useState } from "react";

export function GitHubOrgSetup() {
  const trpc = useTRPC();
  const router = useRouter();
  const queryClient = useQueryClient();
  const { setActive } = useOrganizationList();
  const [error, setError] = useState<string>();

  const { data: pendingInstalls } = useSuspenseQuery(
    trpc.organization.listPendingInstalls.queryOptions()
  );

  const { data: installUrl } = useSuspenseQuery(
    trpc.organization.getGitHubInstallUrl.queryOptions()
  );

  const createMutation = useMutation(
    trpc.organization.createFromPendingInstall.mutationOptions({
      meta: { suppressErrorToast: true },
      onSuccess: async (data) => {
        if (setActive) {
          await setActive({ organization: data.organizationId });
        }
        void queryClient.invalidateQueries({
          queryKey:
            trpc.organization.listUserOrganizations.queryOptions().queryKey,
        });
        router.push(`/${data.slug}`);
      },
      onError: (err) => {
        setError(err.message ?? "Failed to create workspace. Please try again.");
      },
    })
  );

  const hasPending = pendingInstalls.length > 0;

  return (
    <div className="space-y-4">
      {error && <p className="text-destructive text-sm">{error}</p>}

      {hasPending ? (
        <>
          <div className="space-y-3">
            {pendingInstalls.map((install) => (
              <div
                key={install.id}
                className="flex items-center justify-between rounded-lg border border-border bg-card p-4"
              >
                <div className="flex items-center gap-3">
                  {install.providerOrgAvatarUrl ? (
                    <Image
                      alt=""
                      className="rounded-full"
                      height={32}
                      src={install.providerOrgAvatarUrl}
                      width={32}
                    />
                  ) : (
                    <div className="flex h-8 w-8 items-center justify-center rounded-full bg-muted">
                      <Github className="h-4 w-4" />
                    </div>
                  )}
                  <div>
                    <p className="font-medium text-foreground text-sm">
                      {install.providerOrgLogin}
                    </p>
                    <p className="font-mono text-muted-foreground text-xs">
                      lightfast.ai/
                      {install.providerOrgLogin.toLowerCase().replace(/[^a-z0-9-]/g, "")}
                    </p>
                  </div>
                </div>
                <Button
                  disabled={createMutation.isPending}
                  onClick={() => {
                    setError(undefined);
                    createMutation.mutate({
                      pendingInstallId: install.id,
                    });
                  }}
                  size="sm"
                >
                  {createMutation.isPending &&
                  createMutation.variables?.pendingInstallId === install.id ? (
                    <>
                      <Loader2 className="mr-2 h-3 w-3 animate-spin" />
                      Creating...
                    </>
                  ) : (
                    "Create Workspace"
                  )}
                </Button>
              </div>
            ))}
          </div>

          <Button
            asChild
            className="w-full"
            variant="outline"
          >
            <a href={installUrl.url}>
              <Github className="mr-2 h-4 w-4" />
              Install on another organization
            </a>
          </Button>
        </>
      ) : (
        <Button asChild className="w-full">
          <a href={installUrl.url}>
            <Github className="mr-2 h-4 w-4" />
            Install GitHub App
          </a>
        </Button>
      )}
    </div>
  );
}

