import { db } from "@db/app/client";
import {
  gatewayInstallations,
  pendingInstallations,
} from "@db/app/schema";
import { createPlatformCaller } from "@repo/platform-trpc/caller";
import type { TRPCRouterRecord } from "@trpc/server";
import { TRPCError } from "@trpc/server";
import { clerkClient } from "@vendor/clerk/server";
import { and, eq } from "drizzle-orm";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { z } from "zod";
import { userScopedProcedure, verifyOrgMembership } from "../../trpc";

/**
 * Organization router - Clerk-based organization management
 *
 * Phase 1.6: Organizations are managed entirely in Clerk (source of truth)
 * No database table for organizations - Clerk handles all org data
 */
export const organizationRouter = {
  /**
   * List user's organizations from Clerk
   *
   * Returns all organizations the authenticated user belongs to.
   * Used by org-switcher component in the header.
   */
  listUserOrganizations: userScopedProcedure.query(async ({ ctx }) => {
    // userScopedProcedure guarantees clerk-pending or clerk-active
    const userId = ctx.auth.userId;
    const clerk = await clerkClient();

    // Get all organizations the user belongs to from Clerk
    const { data: memberships } =
      await clerk.users.getOrganizationMembershipList({
        userId,
      });

    // Return Clerk organization data directly
    return memberships.map((membership) => {
      const clerkOrg = membership.organization;

      return {
        id: clerkOrg.id, // Clerk org ID
        slug: clerkOrg.slug,
        name: clerkOrg.name,
        role: membership.role,
        imageUrl: clerkOrg.imageUrl,
      };
    });
  }),

  /**
   * Get GitHub App install URL for org creation.
   * No active org required — the install creates a pending installation.
   */
  getGitHubInstallUrl: userScopedProcedure.query(async ({ ctx }) => {
    const platform = await createPlatformCaller();
    const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? "http://localhost:3024";

    return platform.connections.getAuthorizeUrl({
      provider: "github",
      connectedBy: ctx.auth.userId,
      redirectTo: `${appUrl}/account/teams/new`,
    });
  }),

  /**
   * List pending GitHub App installs for the current user.
   * Used by /account/teams/new to show installed orgs ready to become workspaces.
   */
  listPendingInstalls: userScopedProcedure.query(async ({ ctx }) => {
    const rows = await db
      .select({
        id: pendingInstallations.id,
        provider: pendingInstallations.provider,
        providerOrgId: pendingInstallations.providerOrgId,
        providerOrgLogin: pendingInstallations.providerOrgLogin,
        providerOrgAvatarUrl: pendingInstallations.providerOrgAvatarUrl,
        createdAt: pendingInstallations.createdAt,
      })
      .from(pendingInstallations)
      .where(eq(pendingInstallations.connectedBy, ctx.auth.userId));

    return rows;
  }),

  /**
   * Create a Lightfast workspace from a pending GitHub App install.
   * Creates Clerk org, inserts gatewayInstallation, deletes pending row.
   */
  createFromPendingInstall: userScopedProcedure
    .input(z.object({ pendingInstallId: z.string() }))
    .mutation(async ({ ctx, input }) => {
      // 1. Read pending install
      const [pending] = await db
        .select()
        .from(pendingInstallations)
        .where(
          and(
            eq(pendingInstallations.id, input.pendingInstallId),
            eq(pendingInstallations.connectedBy, ctx.auth.userId)
          )
        )
        .limit(1);

      if (!pending) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "Pending install not found",
        });
      }

      // 2. Re-check 1:1 constraint (belt-and-suspenders)
      const existingBinding = await db
        .select({ id: gatewayInstallations.id })
        .from(gatewayInstallations)
        .where(
          and(
            eq(gatewayInstallations.provider, pending.provider),
            eq(gatewayInstallations.providerOrgId, pending.providerOrgId)
          )
        )
        .limit(1);

      if (existingBinding.length > 0) {
        throw new TRPCError({
          code: "CONFLICT",
          message:
            "This GitHub organization is already connected to a workspace",
        });
      }

      // 3. Normalize slug
      const slug = pending.providerOrgLogin
        .toLowerCase()
        .replace(/[^a-z0-9-]/g, "");
      if (!slug) {
        throw new TRPCError({
          code: "BAD_REQUEST",
          message: "GitHub org login produced an invalid slug",
        });
      }

      // 4. Create Clerk org
      const clerk = await clerkClient();
      const clerkOrg = await clerk.organizations.createOrganization({
        name: pending.providerOrgLogin,
        slug,
        createdBy: ctx.auth.userId,
      });

      // 5. Create gatewayInstallations row — if this fails, clean up the Clerk org
      try {
        await db.insert(gatewayInstallations).values({
          provider: pending.provider,
          externalId: pending.externalId,
          connectedBy: pending.connectedBy,
          orgId: clerkOrg.id,
          status: "active",
          providerAccountInfo: pending.providerAccountInfo,
          providerOrgId: pending.providerOrgId,
          providerOrgLogin: pending.providerOrgLogin,
        });
      } catch (insertError) {
        log.error(
          "[organization] gatewayInstallation insert failed, deleting orphaned Clerk org",
          {
            clerkOrgId: clerkOrg.id,
            error: parseError(insertError),
          }
        );
        await clerk.organizations.deleteOrganization(clerkOrg.id);
        throw new TRPCError({
          code: "CONFLICT",
          message:
            "This GitHub organization was just connected to another workspace",
        });
      }

      // 6. Delete pending install
      await db
        .delete(pendingInstallations)
        .where(eq(pendingInstallations.id, pending.id));

      log.info("[organization] created from GitHub install", {
        clerkOrgId: clerkOrg.id,
        slug: clerkOrg.slug,
        providerOrgId: pending.providerOrgId,
      });

      return {
        organizationId: clerkOrg.id,
        slug: clerkOrg.slug ?? slug,
      };
    }),

  /**
   * Create organization
   * Creates a new Clerk organization with the user as admin
   *
   * Used by team creation flow at /account/teams/new
   * Does NOT create a default project - user sets up integrations separately
   */
  create: userScopedProcedure
    .input(
      z.object({
        slug: clerkOrgSlugSchema,
      })
    )
    .mutation(async ({ ctx, input }) => {
      // userScopedProcedure guarantees clerk-pending or clerk-active
      log.info("[organization] create", {
        slug: input.slug,
        userId: ctx.auth.userId,
        authType: ctx.auth.type,
      });

      const clerk = await clerkClient();

      try {
        // Create Clerk organization (slug used for both name and slug)
        const clerkOrg = await clerk.organizations.createOrganization({
          name: input.slug,
          slug: input.slug,
          createdBy: ctx.auth.userId,
        });

        log.info("[organization] create success", {
          organizationId: clerkOrg.id,
          slug: clerkOrg.slug,
        });

        return {
          organizationId: clerkOrg.id,
          slug: clerkOrg.slug || input.slug,
        };
      } catch (error: unknown) {
        log.error("[organization] create failed", {
          slug: input.slug,
          userId: ctx.auth.userId,
          error: parseError(error),
          errorDetails: error,
        });

        // Check for specific Clerk errors
        if (error && typeof error === "object" && "errors" in error) {
          const clerkError = error as {
            errors?: { code: string; message: string }[];
          };

          log.error("[organization] clerk error details", {
            errors: clerkError.errors,
          });

          if (
            clerkError.errors?.[0]?.code === "duplicate_record" ||
            clerkError.errors?.[0]?.code === "form_identifier_exists" ||
            clerkError.errors?.[0]?.message.includes("already exists") ||
            clerkError.errors?.[0]?.message.includes("slug is taken")
          ) {
            throw new TRPCError({
              code: "CONFLICT",
              message: `An organization with the name "${input.slug}" already exists`,
            });
          }
        }

        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Failed to create organization",
          cause: error,
        });
      }
    }),

  /**
   * Update organization name
   * Used by team settings page to update the organization name/slug in Clerk
   *
   * Only organization admins can update the organization name
   */
  updateName: userScopedProcedure
    .input(
      z.object({
        slug: z.string().min(1, "Organization slug is required"),
        name: clerkOrgSlugSchema,
      })
    )
    .mutation(async ({ ctx, input }) => {
      // userScopedProcedure guarantees clerk-pending or clerk-active
      const clerk = await clerkClient();

      try {
        // Get organization by slug
        const org = await clerk.organizations.getOrganization({
          slug: input.slug,
        });

        // Verify user has admin access to the organization
        await verifyOrgMembership({
          clerkOrgId: org.id,
          userId: ctx.auth.userId,
          requireAdmin: true,
        });

        // Update organization in Clerk
        await clerk.organizations.updateOrganization(org.id, {
          name: input.name,
          slug: input.name, // Clerk uses slug for URL-safe names
        });

        log.info("[organization] updateName success", {
          organizationId: org.id,
          slug: input.name,
          userId: ctx.auth.userId,
        });

        return {
          success: true,
          id: org.id, // Return org ID for setActive calls
          name: input.name,
        };
      } catch (error: unknown) {
        // Re-throw TRPCError as-is
        if (error instanceof TRPCError) {
          throw error;
        }

        log.error("[organization] updateName failed", {
          slug: input.slug,
          userId: ctx.auth.userId,
          error: parseError(error),
        });

        // Check for specific Clerk errors
        if (error && typeof error === "object" && "errors" in error) {
          const clerkError = error as {
            errors?: { code: string; message: string }[];
          };

          if (
            clerkError.errors?.[0]?.code === "duplicate_record" ||
            clerkError.errors?.[0]?.code === "form_identifier_exists" ||
            clerkError.errors?.[0]?.message.includes("already exists") ||
            clerkError.errors?.[0]?.message.includes("slug is taken")
          ) {
            throw new TRPCError({
              code: "CONFLICT",
              message: `An organization with the name "${input.name}" already exists`,
            });
          }
        }

        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Failed to update organization",
          cause: error,
        });
      }
    }),
} satisfies TRPCRouterRecord;

